import React from "react";
import Chart from "react-apexcharts";

const Dashboard = () => {
  const chartOptions = {
    chart: {
      id: "basic-bar",
    },
    xaxis: {
      categories: ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul"],
    },
  };

  const chartSeries = [
    {
      name: "Sales",
      data: [30, 40, 35, 50, 49, 60, 70],
    },
  ];

  return (
    <div>
      <h1>Dashboard</h1>
      <div className="kpis">
        <div className="kpi">
          <h2>Total Sales</h2>
          <p>$100,000</p>
        </div>
        <div className="kpi">
          <h2>Total Inspections</h2>
          <p>250</p>
        </div>
        <div className="kpi">
          <h2>Active Users</h2>
          <p>150</p>
        </div>
      </div>
      <Chart
        options={chartOptions}
        series={chartSeries}
        type="line"
        width="500"
      />
    </div>
  );
};

export default Dashboard;
